  'falken:wildpeak-a-t3w': 'https://www.falkentire.com/tires/wildpeak-at3w/wildpeak_at3w.png',
  'falken:wildpeak-m-t': 'https://www.falkentire.com/tires/wildpeak-mt/wildpeak_mt.png',

