  'nitto:terra-grappler-g2': 'https://www.nittotire.com/tires/terra-grappler-g2/terra-grappler-g2.png',
}

/**
 * Normalize a string for lookup (lowercase, replace spaces with dashes)
 */
function normalize(s: string): string {
  return (s || '')
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
}

/**
 * Get tire image URL with fallback chain:
 * 1. API-provided imageUrl (if valid)
 * 2. Model-specific image from mapping
 * 3. Brand-level image from mapping
 * 4. Default fallback image
 */
export function getTireImage(
  imageUrl: string | undefined | null,
  brand: string | undefined | null,
  model: string | undefined | null
): string {
  // 1. Use API image if provided and valid
  if (imageUrl && typeof imageUrl === 'string' && imageUrl.trim()) {
    return imageUrl
  }

  const normalizedBrand = normalize(brand || '')
  const normalizedModel = normalize(model || '')

  // 2. Try model-specific image
  if (normalizedBrand && normalizedModel) {
    const modelKey = `${normalizedBrand}:${normalizedModel}`
    if (MODEL_IMAGES[modelKey]) {
      return MODEL_IMAGES[modelKey]
    }

    // Try partial model match (first word of model)
    const firstModelWord = normalizedModel.split('-')[0]
    for (const [key, url] of Object.entries(MODEL_IMAGES)) {
      if (key.startsWith(`${normalizedBrand}:${firstModelWord}`)) {
        return url
      }
    }
  }

  // 3. Try brand-level image
  if (normalizedBrand && BRAND_IMAGES[normalizedBrand]) {
    return BRAND_IMAGES[normalizedBrand]
  }

  // 4. Default fallback
  return DEFAULT_TIRE_IMAGE
}

/**
 * Check if an image URL is the default fallback
 */
export function isDefaultImage(url: string): boolean {
  return url === DEFAULT_TIRE_IMAGE
}

'use client'

import { useState, useCallback } from 'react'
import { getTireImage, DEFAULT_TIRE_IMAGE, isDefaultImage } from '@/lib/images/tireImageMap'

interface TireImageProps {
  imageUrl?: string | null
  brand?: string | null
  model?: string | null
  alt: string
  className?: string
  size?: 'sm' | 'md' | 'lg'
  showBrandFallback?: boolean
}

const sizeClasses = {
  sm: 'h-24 w-full',
  md: 'h-48 w-full',
  lg: 'h-64 w-full',
}

/**
 * TireImage component with smart fallback chain:
 * 1. API image → 2. Model match → 3. Brand match → 4. Default SVG
 * 
 * Handles loading states and broken images gracefully.
 */
export function TireImage({
  imageUrl,
  brand,
  model,
  alt,
  className = '',
  size = 'md',
  showBrandFallback = true,
}: TireImageProps) {
  const [imgSrc, setImgSrc] = useState(() => getTireImage(imageUrl, brand, model))
  const [hasError, setHasError] = useState(false)
  const [isLoading, setIsLoading] = useState(true)

  const handleError = useCallback(() => {
    setHasError(true)
    setIsLoading(false)
    // Fall back to default image on error
    if (imgSrc !== DEFAULT_TIRE_IMAGE) {
      setImgSrc(DEFAULT_TIRE_IMAGE)
    }
  }, [imgSrc])

  const handleLoad = useCallback(() => {
    setIsLoading(false)
  }, [])

  const sizeClass = sizeClasses[size]
  const isDefault = isDefaultImage(imgSrc)

  // If we're showing the default SVG placeholder
  if (hasError || isDefault) {
    return (
      <div 
        className={`${sizeClass} ${className} grid place-items-center bg-white p-3 text-center rounded-lg`}
      >
        <div>
          {/* SVG Tire Icon */}
          <svg
            className="w-16 h-16 mx-auto text-neutral-300"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
          >
            <circle cx="12" cy="12" r="9" />
            <circle cx="12" cy="12" r="5" />
            <circle cx="12" cy="12" r="2" />
            <path d="M12 3v2M12 19v2M3 12h2M19 12h2M5.6 5.6l1.4 1.4M17 17l1.4 1.4M5.6 18.4l1.4-1.4M17 7l1.4-1.4" />
          </svg>
          <div className="mt-2 text-xs font-semibold text-neutral-500">
            {brand || 'Tire'}
          </div>
          {showBrandFallback && model && (
            <div className="text-[10px] text-neutral-400 truncate max-w-[120px]">
              {model}
            </div>
          )}
        </div>
      </div>
    )
  }

  return (
    <div className={`${sizeClass} ${className} relative bg-white rounded-lg overflow-hidden`}>
      {/* Loading skeleton */}
      {isLoading && (
        <div className="absolute inset-0 bg-neutral-100 animate-pulse flex items-center justify-center">
          <svg
            className="w-12 h-12 text-neutral-300"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
          >
            <circle cx="12" cy="12" r="9" />
            <circle cx="12" cy="12" r="5" />
          </svg>
        </div>
      )}

      {/* Actual image */}
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img
        src={imgSrc}
        alt={alt}
        className={`${sizeClass} object-contain transition-opacity duration-200 ${
          isLoading ? 'opacity-0' : 'opacity-100'
        }`}
        onError={handleError}
        onLoad={handleLoad}
        loading="lazy"
      />
    </div>
  )
}

