      <div className="mt-5 grid gap-4 md:grid-cols-3">
        <EntryTile
          title="Wheel & tire packages"
          subtitle="Pick year/make/model to build a package."
          onClick={() => launch("packages")}
        />
        <EntryTile
          title="Shop tires"
          subtitle="Search tires by size."
          onClick={() => launch("tires", "size")}
        />
        <EntryTile
          title="Shop wheels"
          subtitle="Search wheels (vehicle-based fitment)."
          onClick={() => launch("wheels", "vehicle")}
        />
      </div>
    </div>
  );
}

